import sys

def main():
    N = int(sys.stdin.readline())
    result = []
    for i in range(N + 1):
        min_j = None
        for j in range(1, 10):
            if N % j == 0:
                quotient = N // j
                if i % quotient == 0:
                    if min_j is None or j < min_j:
                        min_j = j
        if min_j is not None:
            result.append(str(min_j))
        else:
            result.append('-')
    print(''.join(result))

main()
